class RunningMeanStd:
    def __init__(self, epsilon: float = 1e-4, shape=()):
        self.mean = np.zeros(shape, dtype=np.float64)
        self.var = np.ones(shape, dtype=np.float64)
        self.count = epsilon

    def update(self, x: np.ndarray):
        x = np.asarray(x, dtype=np.float64)
        batch_mean = x.mean(axis=0)
        batch_var = x.var(axis=0)
        batch_count = x.shape[0] if x.ndim > 0 else 1
        self._update_from_moments(batch_mean, batch_var, batch_count)

    def _update_from_moments(self, batch_mean, batch_var, batch_count):
        delta = batch_mean - self.mean
        total_count = self.count + batch_count
        new_mean = self.mean + delta * batch_count / total_count
        m_a = self.var * self.count
        m_b = batch_var * batch_count
        m2 = m_a + m_b + np.square(delta) * self.count * batch_count / total_count
        new_var = m2 / total_count
        self.mean = new_mean
        self.var = new_var
        self.count = total_count

    @property
    def std(self):
        return np.sqrt(self.var + 1e-8)


class RewardNormalizer:
    def __init__(self, gamma: float = 0.99, clip: float = 10.0):
        self.gamma = gamma
        self.clip = clip
        self.ret = 0.0
        self.rms = RunningMeanStd(shape=())

    def reset(self):
        self.ret = 0.0

    def __call__(self, reward: float) -> float:
        self.ret = self.ret * self.gamma + reward
        self.rms.update(np.array([self.ret]))
        normed = reward / self.rms.std
        return float(np.clip(normed, -self.clip, self.clip))


class Logger:
    def __init__(self, algo: str, log_dir: str):
        stamp = time.strftime("%Y%m%d-%H%M%S")
        self.run_dir = Path(log_dir) / f"{algo}_{stamp}"
        self.run_dir.mkdir(parents=True, exist_ok=True)
        self.writer = SummaryWriter(log_dir=str(self.run_dir))
        self.history_path = self.run_dir / "metrics.jsonl"
        self.recent_rewards = deque(maxlen=20)

    def log(self, step: int, metrics: Dict[str, Any]):
        for key, value in metrics.items():
